### 3. UserService 예상 메서드 시그니처 및 로직

**Service 계층 (마이크로서비스):**

```kotlin
@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {
    // 팔로우 추가
    @Transactional
    fun follow(followerId: String, followeeId: String): FollowEntity {
        // 1. 자신을 팔로우하는지 확인 → 예외 발생
        if (followerId == followeeId) {
            throw IllegalArgumentException("Cannot follow yourself")
        }

        // 2. 대상 유저 존재 여부 확인
        val followee = userRepository.findById(followeeId)
            .orElseThrow { NotFoundException("User not found: $followeeId") }

        // 3. 이미 팔로우하는지 확인
        val existing = followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId)
        if (existing != null) {
            throw IllegalStateException("Already following this user")
        }

        // 4. 팔로우 관계 생성
        val follow = FollowEntity(
            followerId = followerId,
            followeeId = followeeId,
            status = 0 // ACTIVE
        )
        return followRepository.save(follow)
    }

    // 팔로우 취소
    @Transactional
    fun unfollow(followerId: String, followeeId: String): Boolean {
        val follow = followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId)
            ?: throw NotFoundException("Follow relationship not found")
        followRepository.delete(follow)
        return true
    }

    // 팔로우 목록 조회
    @Transactional(readOnly = true)
    fun getFollowings(userId: String, limit: Int = 20, offset: Int = 0): List<UserEntity> {
        return followRepository.findByFollowerId(userId)
            .drop(offset)
            .take(limit)
            .mapNotNull { it.followee }
    }

    // 팔로워 목록 조회
    @Transactional(readOnly = true)
    fun getFollowers(userId: String, limit: Int = 20, offset: Int = 0): List<UserEntity> {
        return followRepository.findByFolloweeId(userId)
            .drop(offset)
            .take(limit)
            .mapNotNull { it.follower }
    }

    // 팔로우 여부 확인
    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean {
        return followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId) != null
    }

    // 팔로우/팔로워 개수
    @Transactional(readOnly = true)
    fun getFollowStats(userId: String): FollowStats {
        return FollowStats(
            followingCount = followRepository.countByFollowerId(userId),
            followerCount = followRepository.countByFolloweeId(userId)
        )
    }
}
```

