### 5. GraphQL Schema 정의 (예상)

```graphql
type Follow {
    id: ID!
    followerId: ID!
    followeeId: ID!
    createdAt: String!
}

type User {
    id: ID!
    nickname: String!
    # ... 기타 필드
    followingCount: Int!
    followerCount: Int!
    isFollowing(targetUserId: ID!): Boolean!
}

input FollowInput {
    followeeId: ID!
}

extend type Query {
    followings(userId: ID!, limit: Int, offset: Int): [User!]!
    followers(userId: ID!, limit: Int, offset: Int): [User!]!
    isFollowing(targetUserId: ID!): Boolean!
    followStats(userId: ID!): FollowStats!
}

extend type Mutation {
    follow(input: FollowInput!): Follow!
    unfollow(followeeId: ID!): Boolean!
}

type FollowStats {
    followingCount: Int!
    followerCount: Int!
}
```

