### 7. GraphQL Controller (예상)

```kotlin
@Controller
class UserController(
    private val userService: UserService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun followings(
        @Argument userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<UserResponse> {
        return userService.getFollowings(userId, limit ?: 20, offset ?: 0)
            .map { it.toResponse() }
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun isFollowing(
        @UserId userId: String,
        @Argument targetUserId: String,
    ): Boolean {
        return userService.isFollowing(userId, targetUserId)
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun follow(
        @UserId userId: String,
        @Argument input: FollowInput,
    ): FollowResponse {
        val result = userService.follow(userId, input.followeeId)
        return FollowResponse(
            id = result.id,
            followerId = result.followerId,
            followeeId = result.followeeId,
            createdAt = result.createdAt.toString()
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun unfollow(
        @UserId userId: String,
        @Argument followeeId: String,
    ): Boolean {
        return userService.unfollow(userId, followeeId)
    }
}
```

