### 8. 테스트 파일 패턴 (예상)

**UserService 테스트:**

```kotlin
@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    @Test
    fun `should follow user successfully`() {
        // given
        val followerId = "user-1"
        val followeeId = "user-2"
        `when`(userRepository.findById(followeeId))
            .thenReturn(Optional.of(UserEntity(id = followeeId)))
        `when`(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(null)

        // when
        val result = userService.follow(followerId, followeeId)

        // then
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followeeId).isEqualTo(followeeId)
        verify(followRepository).save(any())
    }

    @Test
    fun `should throw when following self`() {
        // when & then
        assertThrows<IllegalArgumentException> {
            userService.follow("user-1", "user-1")
        }
    }

    @Test
    fun `should return followings list`() {
        // given
        val userId = "user-1"
        val follows = listOf(
            FollowEntity(followerId = userId, followeeId = "user-2"),
            FollowEntity(followerId = userId, followeeId = "user-3")
        )
        `when`(followRepository.findByFollowerId(userId)).thenReturn(follows)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        verify(followRepository).findByFollowerId(userId)
    }

    @Test
    fun `should throw when unfollowing non-existent relationship`() {
        // given
        `when`(followRepository.findByFollowerIdAndFolloweeId("user-1", "user-2"))
            .thenReturn(null)

        // when & then
        assertThrows<NotFoundException> {
            userService.unfollow("user-1", "user-2")
        }
    }
}
```

