    // 팔로워 목록 조회
    @Transactional(readOnly = true)
    fun getFollowers(userId: String, limit: Int = 20, offset: Int = 0): List<UserEntity> {
        return followRepository.findByFolloweeId(userId)
            .drop(offset)
            .take(limit)
            .mapNotNull { it.follower }
    }

    // 팔로우 여부 확인
    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean {
        return followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId) != null
    }

    // 팔로우/팔로워 개수
    @Transactional(readOnly = true)
    fun getFollowStats(userId: String): FollowStats {
        return FollowStats(
            followingCount = followRepository.countByFollowerId(userId),
            followerCount = followRepository.countByFolloweeId(userId)
        )
    }
}
