### 6. gRPC Service 구현 (예상)

```kotlin
@GrpcService
class UserGrpcService(
    private val userService: UserService,
) : UserServiceGrpc.UserServiceImplBase() {

    override fun follow(
        request: FollowRequest,
        responseObserver: StreamObserver<FollowResponse>,
    ) {
        try {
            userService.follow(request.followerId, request.followeeId)
            val response = FollowResponse.newBuilder()
                .setSuccess(true)
                .setMessage("Follow successful")
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INVALID_ARGUMENT
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }

    override fun unfollow(
        request: UnfollowRequest,
        responseObserver: StreamObserver<UnfollowResponse>,
    ) {
        try {
            userService.unfollow(request.followerId, request.followeeId)
            val response = UnfollowResponse.newBuilder()
                .setSuccess(true)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }

    override fun isFollowing(
        request: IsFollowingRequest,
        responseObserver: StreamObserver<IsFollowingResponse>,
    ) {
        try {
            val isFollowing = userService.isFollowing(
                request.followerId,
                request.followeeId
            )
            val response = IsFollowingResponse.newBuilder()
                .setIsFollowing(isFollowing)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal server error")
                    .asRuntimeException()
            )
        }
    }
}
